10→/*
11→ *  The values used for 'whence' on a Seek call:
12→ */
13→#define	SEEK_SET	0	/* Set position to 'offset' */
14→#define	SEEK_CUR	1	/* Set position to current plus 'offset' */
15→#define	SEEK_END	2	/* Set position to EOF plus 'offset' */
16→
17→/*
18→ *  The structure used to return information on a Stat call:
19→ */
20→struct Stat {
21→    int inum;		/* inode number of file */
22→    int type;		/* type of file (e.g., INODE_REGULAR) */
23→    int size;		/* size of file in bytes */
24→    int nlink;		/* link count of file */
25→};
26→
