 1→#include <stdio.h>
 2→#include <strings.h>
 3→
 4→#include <comp421/yalnix.h>
 5→#include <comp421/iolib.h>
 6→#include <comp421/filesystem.h>
 7→
 8→/*
 9→ *  Works like "ls".
10→ *
11→ *  Uncomment #define below to test symbolic links too.
12→ */
13→
14→/* #define TEST_SYMLINKS */
15→
16→int
17→main(int argc, char **argv)
18→{
19→    int fd;
20→    int nch;
21→    struct dir_entry entry;
22→    char *name;
23→    struct Stat sb;
24→    char buffer[DIRNAMELEN+1];
25→#ifdef  TEST_SYMLINKS
26→    char link[MAXPATHNAMELEN+1];
27→#endif
28→    char typechar;
29→
30→    name = (argc > 1) ? argv[1] : ".";
31→
32→    if (ChDir(name) == ERROR) {
33→	fprintf(stderr, "Can't ChDir to %s\n", name);
34→	Shutdown();
35→	Exit(1);
36→    }
37→	
38→    if ((fd = Open(".")) == ERROR) {
39→	fprintf(stderr, "Can't Open . in %s\n", name);
40→	Shutdown();
41→	Exit(1);
42→    }
43→
44→    while (1) {
45→	nch = Read(fd, (char *)&entry, sizeof(entry));
46→	if (nch == 0)
47→	    break;
48→	else if (nch < 0) {
49→	    fprintf(stderr, "ERROR Reading from directory\n");
50→	    Shutdown();
51→	    Exit(1);
52→	} else if (nch != sizeof(entry)) {
53→	    fprintf(stderr, "Read wrong byte count %d\n", nch);
54→	    Shutdown();
55→	    Exit(1);
56→	}
57→	if (entry.inum == 0) continue;
58→	bcopy(entry.name, buffer, DIRNAMELEN);
59→	buffer[DIRNAMELEN] = '\0';
60→	/* was LinkStat, when supporting symlinks ??? */
61→	if (Stat(buffer, &sb) == ERROR) {
62→	    fprintf(stderr, "Can't LinkStat %s\n", buffer);
63→	    Shutdown();
64→	    Exit(1);
65→	}
66→	switch (sb.type) {
67→	    case INODE_REGULAR:	typechar = ' '; break;
68→	    case INODE_DIRECTORY:	typechar = 'd'; break;
69→#ifdef	TEST_SYMLINKS
70→	    case INODE_SYMLINK:	typechar = 's'; break;
71→#endif
72→	    default:		typechar = '?'; break;
73→	}
74→	printf("%4d %c %3d %5d %s",
75→	    entry.inum, typechar, sb.nlink, sb.size, buffer);
76→#ifdef	TEST_SYMLINKS
77→	if (sb.type == INODE_SYMLINK) {
78→	    nch = ReadLink(buffer, link, sizeof(link));
79→	    if (nch == ERROR) {
80→		fprintf(stderr, "Can't ReadLink %s\n",
81→		    buffer);
82→		Shutdown();
83→		Exit(1);
84→	    }
85→	    link[nch] = '\0';
86→	    printf(" -> %s\n", link);
87→	}
88→	else
89→#endif
90→	    printf("\n");
91→    }
92→
93→    Shutdown();
94→}
